# Base module containing interfaces and abstract classes for shapes

interface IShape:
    def area(self) -> float: ...

    def perimeter(self) -> float: ...


interface ITransformable:
    def scale(self, factor: float) -> None: ...


@abstract
class ShapeBase:
    tag: str

    def __init__(self):
        self.tag = "unknown"

    @abstract
    def describe(self) -> str: ...


@abstract
class Polygon(ShapeBase):
    sides: int

    @abstract
    def get_side_count(self) -> int: ...

