# Concrete shape implementations extending base classes and interfaces

from shapes_base import IShape, ITransformable, ShapeBase, Polygon

class Rectangle(Polygon, IShape, ITransformable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__()
        self.width = width
        self.height = height
        self.tag = "RECT"
        self.sides = 4

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    def describe(self) -> str:
        return "Rectangle with tag=" + self.tag

    def get_side_count(self) -> int:
        return self.sides


class Circle(ShapeBase, IShape, ITransformable):
    radius: float

    def __init__(self, radius: float):
        super().__init__()
        self.radius = radius
        self.tag = "CIRC"

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

    def describe(self) -> str:
        return "Circle with tag=" + self.tag


class ShapeCollection:
    items: list[IShape]

    def __init__(self):
        self.items = []

    def add(self, shape: IShape) -> None:
        self.items.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.items:
            total = total + shape.area()
        return total
